mapper.select:
SELECT communityno, cat_no, memberno, nickname, cateno, title, viewcnt, replycnt, rdate, thumb FROM ( SELECT communityno, cat_no, memberno, nickname, cateno, title, viewcnt, replycnt, rdate, thumb, row_number() OVER (ORDER BY communityno DESC) as r FROM ( SELECT c.communityno, c.cat_no, c.memberno, c.nickname, c.cateno, c.title, c.viewcnt, c.replycnt, c.rdate,
( SELECT fupname FROM attachfile WHERE communityno = c.communityno AND rownum = 1 ) as thumb
FROM community c
AND c.cat_no = #{cat_no}
AND c.cateno = #{cateno}
AND ( c.title LIKE '%' || #{word} || '%' OR c.content LIKE '%' || #{word} || '%' OR c.word LIKE '%' || #{word} || '%' )
) ) WHERE r >= #{start_num} AND r <= #{end_num}

SELECT COUNT(*) as cnt
FROM community


    AND memberno = #{memberno, jdbcType=INTEGER}



    AND cat_no = #{cat_no, jdbcType=INTEGER}



    AND cateno = #{cateno, jdbcType=INTEGER}



    AND (title LIKE '%' || #{word} || '%' 
         OR content LIKE '%' || #{word} || '%' 
         OR word LIKE '%' || #{word} || '%')

SELECT communityno, cat_no, memberno, nickname, cateno, title, content, viewcnt, recom, replycnt, rdate, word
FROM community
WHERE communityno = #{communityno}

mapper.update:
UPDATE community
SET title = #{title},
    content = #{content},
    word = #{word},
    cateno = #{cateno}
WHERE communityno = #{communityno}

UPDATE community
SET replycnt = replycnt ${mode} 1
WHERE communityno = #{communityno}
